@Component({ templateUrl: './dashboard.page.html' })
export class DashboardPage {
  data = inject(DashboardBff).summary();
}

@Component({ selector: 'app-revenue-card', templateUrl: './revenue-card.component.html' })
export class RevenueCardComponent {
  revenue = input.required<RevenueView>();
}

@Injectable({ providedIn: 'root' })
export class DashboardBff {
  summary() {
    return this.http.get<DashboardView>('/bff/dashboard');
  }
}

@Injectable({ providedIn: 'root' })
export class TicketBff {
  reopen(ticketId: string) {
    return this.http.post(`/bff/tickets/${ticketId}/reopen`, {});
  }
}

export type DashboardView = {
  revenue: RevenueView;
  tickets: TicketSummaryView;
  alerts: AlertView[];
};

router.get('/dashboard', async (_req, res) => {
  const [revenue, tickets, alerts] = await Promise.all([sales(), support(), risk()]);
  res.json({ revenue, tickets, alerts });
});
